// Pre-process GitHub Issue webhook payload.
//
// Repo→project mapping is NO LONGER hard-coded here. The dashboard owns it
// (UI: Sidebar → Repo → Project Map). The next node calls
// /api/repo-map/lookup against dashboard-api.
//
// You can still pass `?project=<id>` on the webhook URL to override per-hook.
const body = $input.first().json.body || $input.first().json;
const query = $input.first().json.query || {};
const issue = body.issue;
const action = body.action;
if (!issue) { throw new Error('Payload has no `issue` — is this a GitHub issue webhook?'); }
if (action !== 'opened' && action !== 'reopened') {
  return [{ json: { skipped: true, action } }];
}

const repo = (body.repository && body.repository.full_name) || '';
if (!repo) { throw new Error('Payload has no repository.full_name'); }

const overrideProjectId = query.project ? parseInt(query.project, 10) : null;

return [{
  json: {
    skipped: false,
    action,
    repo,
    overrideProjectId,
    issue,
    _meta: { issue_url: issue.html_url, issue_number: issue.number, repo },
  },
}];

// Build the Vikunja task using the dashboard-resolved project_id
// (or the per-hook override if present).
const lookup = $input.first().json;
const parsed = $('Parse GitHub payload').first().json;
const issue = parsed.issue;
const repo = parsed.repo;
const projectId = parsed.overrideProjectId || lookup.project_id;
if (!projectId) { throw new Error(`No project_id resolved for repo '${repo}'`); }

const labels = (issue.labels || []).map(l => l.name).filter(Boolean);
const description = [
  `**GitHub Issue:** ${issue.html_url}`,
  '',
  `**Repo:** ${repo}`,
  `**Author:** @${(issue.user && issue.user.login) || 'unknown'}`,
  labels.length ? `**Labels:** ${labels.map(l => `\`${l}\``).join(', ')}` : '',
  '',
  '---',
  '',
  issue.body || '_(no description)_',
].filter(Boolean).join('\n');

return [{
  json: {
    project_id: projectId,
    task: {
      title: `[${repo.split('/').pop() || 'issue'}] ${issue.title}`,
      description,
    },
    _meta: parsed._meta,
    _mapping_source: lookup.source,
  },
}];
